+fn parse_void_descriptor(name: &str) -> bool {
+    let descriptor = name
+        .strip_prefix('|')
+        .or_else(|| name.strip_prefix('<'))
+        .or_else(|| name.strip_prefix('>'))
+        .unwrap_or(name);
+    descriptor == "V"
+        || descriptor
+            .strip_prefix('V')
+            .is_some_and(|suffix| !suffix.is_empty() && suffix.parse::<usize>().is_ok())
+}
